}

export default async function emulatorInteract({ data = {}, emulator }) {
  const xpath = data.xpath;
  const action = data.action || "click";

  // 解析 value 参数（可能是 JSON 字符串）
  let value = data.value;
  if (typeof value === "string") {
    try {
      value = JSON.parse(value);
    } catch (e) {
      // 如果不是 JSON，保持原字符串
    }
  }

  // 解析 options 参数（可能是 JSON 字符串）
  let options = data.options || {};
  if (typeof options === "string") {
    try {
      options = JSON.parse(options);
    } catch (e) {
      options = {};
    }
  }

  if (!xpath) {
    throw new Error("xpath 参数是必需的");
  }

  const iframe = emulator.iframe;
  if (!iframe) {
    throw new Error("无法访问模拟器的 iframe");
  }

  // 获取模拟器的 document
  const emulatorDocument =
    iframe.contentDocument || iframe.contentWindow.document;

  if (!emulatorDocument) {
    throw new Error("无法访问模拟器的 document");
  }

  // 使用 XPath 查找元素
  const result = emulatorDocument.evaluate(
    xpath,
    emulatorDocument,
    null,
    XPathResult.FIRST_ORDERED_NODE_TYPE,
    null,
  );

  const element = result.singleNodeValue;

  if (!element) {
    throw new Error(`未找到匹配 XPath 的元素: ${xpath}`);
  }

  // 执行交互操作
  try {
    const actionResult = await performAction(element, action, value, options);
    return {
      success: true,
      action,
      xpath,
      ...actionResult,
    };
  } catch (err) {
    throw new Error(`执行操作失败: ${err.message}`);
  }
}

/**
 * 执行交互操作
 */
async function performAction(element, action, value, options) {
  switch (action) {
    case "click":
      return await clickElement(element, options);

    case "input":
      return await inputElement(element, value, options);

    case "focus":
      return focusElement(element);

    case "blur":
      return blurElement(element);

    case "scroll":
      return scrollElement(element, options);

    case "select":
      return selectElement(element, value, options);

    case "clear":
      return clearElement(element);

    case "hover":
      return hoverElement(element);

    case "getAttribute":
      return getAttribute(element, value);

    case "setValue":
      return setValue(element, value);

    default:
      throw new Error(`不支持的操作类型: ${action}`);
  }
}

/**
 * 点击元素
 */
async function clickElement(element, options = {}) {
  const { doubleClick = false, button = "left" } = options;

  // 滚动到元素可见
  element.scrollIntoView({ behavior: "smooth", block: "center" });

  // 等待滚动完成
  await new Promise((resolve) => setTimeout(resolve, 100));

  // 创建鼠标事件
  const rect = element.getBoundingClientRect();
  const centerX = rect.left + rect.width / 2;
  const centerY = rect.top + rect.height / 2;

  // 模拟鼠标移动
  const moveEvent = new MouseEvent("mousemove", {
    bubbles: true,
    cancelable: true,
    view: window,
    clientX: centerX,
    clientY: centerY,
  });
  element.dispatchEvent(moveEvent);

  // 模拟鼠标悬停
  const overEvent = new MouseEvent("mouseover", {
    bubbles: true,
    cancelable: true,
    view: window,
    clientX: centerX,
    clientY: centerY,
  });
  element.dispatchEvent(overEvent);

  // 模拟鼠标按下
  const downEvent = new MouseEvent("mousedown", {
    bubbles: true,
    cancelable: true,
    view: window,
    clientX: centerX,
    clientY: centerY,
    button: button === "right" ? 2 : button === "middle" ? 1 : 0,
  });
  element.dispatchEvent(downEvent);

  // 模拟鼠标释放
  const upEvent = new MouseEvent("mouseup", {
    bubbles: true,
    cancelable: true,
    view: window,
    clientX: centerX,
    clientY: centerY,
    button: button === "right" ? 2 : button === "middle" ? 1 : 0,
  });
  element.dispatchEvent(upEvent);

  // 模拟点击
  const clickEvent = new MouseEvent("click", {
    bubbles: true,
    cancelable: true,
    view: window,
    clientX: centerX,
    clientY: centerY,
    button: button === "right" ? 2 : button === "middle" ? 1 : 0,
  });
  element.dispatchEvent(clickEvent);

  // 如果是双击
  if (doubleClick) {
    await new Promise((resolve) => setTimeout(resolve, 50));
    const dblClickEvent = new MouseEvent("dblclick", {
      bubbles: true,
      cancelable: true,
      view: window,
      clientX: centerX,
      clientY: centerY,
    });
    element.dispatchEvent(dblClickEvent);
  }

  return {
    message: doubleClick ? "已双击元素" : "已点击元素",
    position: { x: centerX, y: centerY },
  };
}

/**
 * 输入文本
 */
async function inputElement(element, value, options = {}) {
  if (value === undefined || value === null) {
    throw new Error("input 操作需要提供 value 参数");
  }

  const { clear = false, delay = 0 } = options;

  // 聚焦元素
  element.focus();

  // 如果需要清空
  if (clear) {
    element.value = "";
  }

  // 如果有延迟，模拟逐字输入
  if (delay > 0) {
    const currentValue = element.value || "";
    for (let i = 0; i < value.length; i++) {
      element.value = currentValue + value.substring(0, i + 1);
      element.dispatchEvent(new Event("input", { bubbles: true }));
      await new Promise((resolve) => setTimeout(resolve, delay));
    }
  } else {
    // 直接设置值
    element.value = value;
    element.dispatchEvent(new Event("input", { bubbles: true }));
    element.dispatchEvent(new Event("change", { bubbles: true }));
  }

  return {
    message: "已输入文本",
    value: value,
  };
}

/**
 * 聚焦元素
 */
function focusElement(element) {
  element.focus();
  return { message: "已聚焦元素" };
}

/**
 * 失焦元素
 */
function blurElement(element) {
  element.blur();
  return { message: "已失焦元素" };
}

/**
 * 滚动到元素
 */
function scrollElement(element, options = {}) {
  const { behavior = "smooth", block = "center", inline = "nearest" } = options;

  element.scrollIntoView({ behavior, block, inline });

  return {
    message: "已滚动到元素",
    options: { behavior, block, inline },
  };
}

/**
 * 选择文本
 */
function selectElement(element, value, options = {}) {
  if (element.tagName === "INPUT" || element.tagName === "TEXTAREA") {
    if (value) {
      // 选择指定范围的文本
      const [start, end] = Array.isArray(value) ? value : [0, element.value.length];
      element.setSelectionRange(start, end);
    } else {
      // 选择全部文本
      element.select();
    }
    return { message: "已选择文本", selectedText: element.value.substring(element.selectionStart, element.selectionEnd) };
  } else {
    // 对于其他元素，尝试选择其文本内容
    const selection = window.getSelection();
    const range = document.createRange();
    range.selectNodeContents(element);
    selection.removeAllRanges();
    selection.addRange(range);
    return { message: "已选择元素内容" };
  }
}

/**
 * 清空输入框
 */
function clearElement(element) {
  if (element.tagName === "INPUT" || element.tagName === "TEXTAREA") {
    element.value = "";
    element.dispatchEvent(new Event("input", { bubbles: true }));
    element.dispatchEvent(new Event("change", { bubbles: true }));
    return { message: "已清空输入框" };
  } else {
    throw new Error("只能清空 INPUT 或 TEXTAREA 元素");
  }
}

/**
 * 鼠标悬停
 */
function hoverElement(element) {
  const rect = element.getBoundingClientRect();
  const centerX = rect.left + rect.width / 2;
  const centerY = rect.top + rect.height / 2;

  const moveEvent = new MouseEvent("mousemove", {
    bubbles: true,
    cancelable: true,
    view: window,
    clientX: centerX,
    clientY: centerY,
  });
  element.dispatchEvent(moveEvent);

  const overEvent = new MouseEvent("mouseover", {
    bubbles: true,
    cancelable: true,
    view: window,
    clientX: centerX,
    clientY: centerY,
  });
  element.dispatchEvent(overEvent);

  return {
    message: "已悬停元素",
    position: { x: centerX, y: centerY },
  };
}

/**
 * 获取属性值
 */
function getAttribute(element, attributeName) {
  if (!attributeName) {
    throw new Error("getAttribute 操作需要提供 value 参数（属性名）");
  }

  const value = element.getAttribute(attributeName);
  return {
    message: "已获取属性值",
    attribute: attributeName,
    value: value,
  };
}

/**
 * 设置属性值
 */
function setValue(element, value) {
  if (!value || typeof value !== "object") {
    throw new Error("setValue 操作需要提供 value 参数（对象格式：{ name: '属性名', value: '属性值' }）");
  }

  const { name, value: attrValue } = value;
  if (!name) {
    throw new Error("setValue 操作需要提供属性名");
  }

  element.setAttribute(name, attrValue || "");
  return {
    message: "已设置属性值",
    attribute: name,
    value: attrValue,
  };
}

export default async function emulatorNavigate({
  data = {},
  content,
  emulator,
}) {
  const { action, url } = data;

  if (action === "current-info") {
    const iframe = emulator.iframe;
    return {
      url: iframe?.src || "",
    };
  }

  if (action === "reload") {
    try {
      const iframe = emulator.iframe;
      if (!iframe) {
        return { success: false, error: "No iframe available" };
      }
      emulator.iframeLoaded = false;
      const loadPromise = listenIframeLoad(iframe);
      iframe.src = iframe.src;
      await loadPromise;
      return {
        success: true,
        url: iframe.src,
      };
    } catch (err) {
      return {
        success: false,
        error: err.message,
      };
    }
  }

  if (action === "go") {
    try {
      if (!url) {
        return { success: false, error: "No URL provided" };
      }
      emulator.iframeLoaded = false;

      let iframe = emulator.iframe;
      let loadPromise;

      if (iframe) {
        // iframe 已存在，先注册监听器再更新 URL
        loadPromise = listenIframeLoad(iframe);
        emulator.iframeUrl = url;
      } else {
        // iframe 不存在，先设置 URL 触发创建，再等待并监听
        emulator.iframeUrl = url;
        iframe = await pollIframe(emulator);
        loadPromise = listenIframeLoad(iframe);
      }

      await loadPromise;
      return {
        success: true,
        url: iframe.src,
      };
    } catch (err) {
      return {
        success: false,
        error: err.message,
      };
    }
  }
}

function listenIframeLoad(iframe, timeout = 30000) {
  return new Promise((resolve, reject) => {
    const timer = setTimeout(() => {
      cleanup();
      reject(new Error("Iframe load timeout"));
    }, timeout);
    const onLoad = () => {
      cleanup();
      resolve();
    };
    const onError = () => {
      cleanup();
      reject(new Error("Iframe load failed"));
    };
    const cleanup = () => {
      clearTimeout(timer);
      iframe.removeEventListener("load", onLoad);
      iframe.removeEventListener("error", onError);
    };
    iframe.addEventListener("load", onLoad);
    iframe.addEventListener("error", onError);
  });
}

function pollIframe(emulator, timeout = 5000) {
  return new Promise((resolve, reject) => {
    const iframe = emulator.iframe;
    if (iframe) {
      resolve(iframe);
      return;
    }
    const timer = setTimeout(() => {
      clearInterval(interval);
      reject(new Error("Iframe not available"));
    }, timeout);
    const interval = setInterval(() => {
      const iframe = emulator.iframe;
      if (iframe) {
        clearTimeout(timer);
        clearInterval(interval);
        resolve(iframe);
      }
    }, 50);
  });
}

export default async function fetchUrl({ data = {}, content }) {
  const {
    url,
    maxSize = 32 * 1024, // 32KB
    cleanHTML = true, // 如果遇到是html内容，是否清理多余标签，只返回包含文本的内容
  } = data;

  const response = await fetch(url);

  if (!response.ok) {
    throw new Error(`HTTP error! status: ${response.status}`);
  }

  data = await response.text();

  // 确定是html内容，才清理多余标签
  if (cleanHTML && data.toLocaleLowerCase().includes("<!doctype html")) {
    data = clearHTML(data);
  }

  if (maxSize && data.length > maxSize) {
    data = data.slice(0, maxSize);
  }

  return data;
}

const clearHTML = (html) => {
  const bodyMatch = html.match(/<body[^>]*>([\s\S]*?)<\/body>/i);
  let bodyContent = bodyMatch ? bodyMatch[1] : html;
  bodyContent = bodyContent.replace(/<script[^>]*>[\s\S]*?<\/script>/gi, "");
  bodyContent = bodyContent.replace(/<svg[^>]*>[\s\S]*?<\/svg>/gi, "");
  bodyContent = bodyContent.replace(/<style[^>]*>[\s\S]*?<\/style>/gi, "");
  bodyContent = bodyContent.replace(
    /<noscript[^>]*>[\s\S]*?<\/noscript>/gi,
    "",
  );
  bodyContent = bodyContent.replace(/<!--[\s\S]*?-->/g, "");
  bodyContent = bodyContent.replace(/<iframe[^>]*>[\s\S]*?<\/iframe>/gi, "");

  const template = document.createElement("template");
  template.innerHTML = bodyContent;
  const allowedAttrs = [
    "href",
    "src",
    "alt",
    "title",
    "role",
    "aria-label",
    "aria-labelledby",
    "aria-describedby",
    "aria-hidden",
    "aria-expanded",
    "aria-disabled",
    "aria-pressed",
    "aria-checked",
    "aria-selected",
    "for",
    "type",
    "name",
    "value",
    "placeholder",
    "disabled",
    "checked",
    "selected",
    "multiple",
    "maxlength",
    "minlength",
    "pattern",
    "required",
    "readonly",
  ];
  template.content.querySelectorAll("*").forEach((el) => {
    const attrs = [...el.attributes];
    attrs.forEach((attr) => {
      if (!allowedAttrs.includes(attr.name) && !attr.name.startsWith("aria-")) {
        el.removeAttribute(attr.name);
      }
    });
  });
  const removeEmpty = (el) => {
    const children = [...el.childNodes];
    children.forEach((child) => {
      if (child.nodeType === 1) {
        removeEmpty(child);
      }
    });
    if (
      el.textContent.trim() === "" &&
      !el.hasAttribute("src") &&
      !el.hasAttribute("href")
    ) {
      el.remove();
    }
  };
  removeEmpty(template.content);
  const simplifyWrappers = (el) => {
    const children = [...el.childNodes];
    children.forEach((child) => {
      if (child.nodeType === 1) {
        simplifyWrappers(child);
        const tagName = child.tagName.toLowerCase();
        if (
          [
            "span",
            "b",
            "i",
            "u",
            "strong",
            "em",
            "small",
            "mark",
            "sub",
            "sup",
          ].includes(tagName)
        ) {
          const textContent = child.textContent;
          const importantAttrs = ["href", "src", "alt", "title", "role"];
          const hasImportantAttr = [...child.attributes].some(
            (attr) =>
              importantAttrs.includes(attr.name) ||
              attr.name.startsWith("aria-"),
          );
          if (
            child.childNodes.length === 1 &&
            child.childNodes[0].nodeType === 3 &&
            !hasImportantAttr
          ) {
            el.replaceChild(document.createTextNode(textContent), child);
          }
        }
      }
    });
  };
  simplifyWrappers(template.content);
  const unwrapNesting = (el) => {
    const children = [...el.childNodes];
    children.forEach((child) => {
      if (child.nodeType === 1) {
        unwrapNesting(child);
        const importantAttrs = [
          "href",
          "src",
          "alt",
          "title",
          "role",
          "for",
          "type",
          "name",
          "value",
          "placeholder",
          "disabled",
          "checked",
          "selected",
        ];
        const hasImportantAttr = [...child.attributes].some(
          (attr) =>
            importantAttrs.includes(attr.name) || attr.name.startsWith("aria-"),
        );
        if (
          child.childNodes.length === 1 &&
          child.childNodes[0].nodeType === 1 &&
          !hasImportantAttr
        ) {
          const inner = child.childNodes[0];
          el.replaceChild(inner.cloneNode(true), child);
        }
      }
    });
  };
  unwrapNesting(template.content);
  return template.innerHTML;
};

