export default async function fs({ data = {}, content }) {
  const { mode, path, targetPath, targetName } = data;

  if (!mode) {
    throw new Error("mode is required");
  }
  if (!path) {
    throw new Error("path is required");
  }

  if (mode === "exists") {
    try {
      const testHandle = await get(path);
      return testHandle ? true : false;
    } catch (e) {
      return false;
    }
  }

  const handle = await get(path, {
    create:
      mode === "write" || mode === "mkdir"
        ? mode === "mkdir"
          ? "dir"
          : "file"
        : undefined,
  });

  if (mode === "write") {
    if (!content) {
      throw new Error("没有内容，无法写入");
    }

    const textarea = document.createElement("textarea");
    textarea.innerHTML = content;
    let textToWrite = textarea.value.trim();

    if (content.startsWith(`<template page="">`)) {
      textToWrite = textToWrite.replace(
        '<template page="">',
        "<template page>",
      );
    } else if (content.startsWith(`<template component="">`)) {
      textToWrite = textToWrite.replace(
        '<template component="">',
        "<template component>",
      );
    }

    if (!textToWrite) {
      throw new Error("没有文本内容，无法写入");
    }

    await handle.write(textToWrite);

    return true;
  }

  if (mode === "read") {
    const content = await handle.text();
    return content;
  }

  if (mode === "delete") {
    await handle.remove();
    return true;
  }

  if (mode === "info") {
    const file = await handle.file();
    const lastModified = await handle.lastModified();
    return {
      kind: handle.kind,
      name: handle.name,
      path: handle.path,
      size: file.size,
      lastModified,
    };
  }

  if (mode === "list") {
    if (handle.kind !== "dir") {
      throw new Error("Path is not a directory");
    }

    const items = [];
    await handle.forEach((handle) => {
      items.push({
        name: handle.name,
        kind: handle.kind,
        path: handle.path,
      });
    });
    return items;
  }

  if (mode === "mkdir") {
    return true;
  }

  if (mode === "move") {
    if (!targetPath) {
      throw new Error("targetPath is required for move operation");
    }
    const targetDir = await get(targetPath, { create: "dir" });
    const movedHandle = await handle.moveTo(targetDir, targetName);
    return {
      kind: movedHandle.kind,
      name: movedHandle.name,
      path: movedHandle.path,
    };
  }

  if (mode === "copy") {
    if (!targetPath) {
      throw new Error("targetPath is required for copy operation");
    }
    const targetDir = await get(targetPath, { create: "dir" });
    const copiedHandle = await handle.copyTo(targetDir, targetName);
    return {
      kind: copiedHandle.kind,
      name: copiedHandle.name,
      path: copiedHandle.path,
    };
  }

  throw new Error(`Unknown mode: ${mode}`);
}

