export default async ({ data = {}, content }) => {
  const { projectPath } = data;

  if (!projectPath) {
    throw new Error("projectPath is required");
  }

  const projectDir = await get(projectPath);

  const aimapList = await collectAimapFiles(projectDir, projectPath);

  return {
    aimaps: aimapList,
  };
};

async function collectAimapFiles(dir, basePath, currentPath = "") {
  const aimapList = [];

  try {
    const aimapDir = await dir.get(".aimap");
    if (aimapDir?.kind === "dir") {
      for await (const [name, handle] of aimapDir.entries()) {
        if (handle.kind === "file" && name.endsWith(".md")) {
          try {
            const content = await handle.text();
            const originalFileName = name.slice(0, -3);
            aimapList.push({
              path: currentPath
                ? `${currentPath}/${originalFileName}`
                : originalFileName,
              aimapPath: currentPath
                ? `${currentPath}/.aimap/${name}`
                : `.aimap/${name}`,
              content: content.trim(),
            });
          } catch (error) {
            console.error(`Error reading aimap file ${name}:`, error);
          }
        }
      }
    }
  } catch (e) {}

  for await (const [name, handle] of dir.entries()) {
    if (handle.kind === "dir" && name !== ".aimap" && !name.startsWith(".")) {
      const subPath = currentPath ? `${currentPath}/${name}` : name;
      aimapList.push(...(await collectAimapFiles(handle, basePath, subPath)));
    }
  }

  return aimapList;
}

import yaml from "/npm/js-yaml@4.1.1/dist/js-yaml.min.mjs";
import { get } from "/nos/fs/main.js";

export default async function getCapability({ data = {}, content }) {
  const { all, name, file } = data;

  await new Promise((resolve) => setTimeout(resolve, 500));

  if (all) {
    const capabilityDesc = [];

    try {
      const capDir = await get("mazmot/capabilities");

      if (capDir) {
        for await (const [capabilityName, handle] of capDir.entries()) {
          if (handle.kind === "dir") {
            const skillFile = await get(
              `mazmot/capabilities/${capabilityName}/SKILL.md`,
              { create: false },
            );

            if (skillFile) {
              const capabilityMd = await skillFile.text();

              if (!capabilityMd.trim()) {
                continue;
              }

              const frontMatterMatch = capabilityMd.match(
                /^---\n([\s\S]*?)\n---/,
              );
              const yamlConfig = yaml.load(frontMatterMatch[1]);

              const desc = yamlConfig.description;
              delete yamlConfig.description;

              capabilityDesc.push({
                ...yamlConfig,
                name: capabilityName,
                desc,
              });
            }
          }
        }
      }
    } catch (error) {
      console.error("Error reading capabilities:", error);
    }

    return capabilityDesc;
  }

  if (name) {
    try {
      const filePath = file
        ? `mazmot/capabilities/${name}/${file}`
        : `mazmot/capabilities/${name}/SKILL.md`;

      const fileHandle = await get(filePath);

      if (!fileHandle) {
        if (file) {
          throw new Error(`File "${file}" not found in capability "${name}"`);
        }
        return {
          name: name,
          file: file || "SKILL.md",
          error: "Capability not found",
        };
      }

      const fileContent = await fileHandle.text();

      if (!fileContent.trim()) {
        if (file) {
          throw new Error(`File "${file}" in capability "${name}" is empty`);
        }
        return {
          name: name,
          file: file || "SKILL.md",
          error: "File is empty",
        };
      }

      return {
        name: name,
        file: file || "SKILL.md",
        content: fileContent,
      };
    } catch (error) {
      if (
        error.message.includes("not found") ||
        error.message.includes("empty")
      ) {
        throw error;
      }
      return {
        name: name,
        file: file || "SKILL.md",
        error: "Capability not found",
      };
    }
  }
}

